namespace BgControls.Windows.Input.Touch;/// <summary>/// 结束滑动惯性操作的脉冲信号类./// </summary>internal class FinishSwipeInertiaPulse{    /// <summary>    /// Initializes a new instance of the <see cref="FinishSwipeInertiaPulse"/> class.    /// </summary>    /// <param name="element">触发该脉冲关联的 UI 元素.</param>    public FinishSwipeInertiaPulse(UIElement element)    {        // 验证传入的元素是否为空.        ArgumentNullException.ThrowIfNull(element, nameof(element));        // 设置关联的 UI 元素.        this.Element = element;    }    /// <summary>    /// Gets 关联的 UI 元素.    /// </summary>    public UIElement Element { get; }}